import { mkdtempSync, writeFileSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest'
import { evaluateInterviewObjectives } from '../../../src/main/objectiveEvaluationService'
import * as repository from '../../../src/main/db/repository'
import { initStore } from '../../../src/main/db/store'
import type { Interview } from '../../../src/renderer/src/types/domain'

const harness = vi.hoisted(() => {
  /** Jerarquía espejo de la del SDK: instanceof debe funcionar en mapSdkError. */
  class APIError extends Error {}
  class AuthenticationError extends APIError {}
  class RateLimitError extends APIError {}
  class APIConnectionError extends APIError {}
  return {
    create: vi.fn(),
    errors: { APIError, AuthenticationError, RateLimitError, APIConnectionError }
  }
})

vi.mock('@anthropic-ai/sdk', () => {
  class MockAnthropic {
    static APIError = harness.errors.APIError
    static AuthenticationError = harness.errors.AuthenticationError
    static RateLimitError = harness.errors.RateLimitError
    static APIConnectionError = harness.errors.APIConnectionError
    readonly messages = { create: harness.create }
  }
  return { default: MockAnthropic }
})

vi.mock('electron', () => ({
  app: {
    getPath: (): string => {
      throw new Error('app.getPath no debe usarse en tests: initStore recibe baseDir inyectado')
    }
  },
  safeStorage: {
    isEncryptionAvailable: (): boolean => true,
    encryptString: (plain: string): Buffer => Buffer.from(plain, 'utf8'),
    decryptString: (blob: Buffer): string => blob.toString('utf8')
  },
  // noteService importa dialog en el top-level (readTranscriptLines vive ahí)
  dialog: {},
  BrowserWindow: {
    getAllWindows: (): unknown[] => []
  }
}))

/** Respuesta del SDK con bloque thinking + text y usage medible (SPEC-021). */
function sdkResponse(text: string): unknown {
  return {
    stop_reason: 'end_turn',
    usage: { input_tokens: 1000, output_tokens: 200 },
    content: [
      { type: 'thinking', thinking: 'razonamiento interno' },
      { type: 'text', text }
    ]
  }
}

const VALID_JSON = JSON.stringify({
  evaluations: [
    { met: true, reason: 'Se obtuvo el dato concreto con cifras reales.' },
    { met: false, reason: 'No se llegó a tocar este tema con hechos pasados.' }
  ]
})

let dataDir = ''

/** Escribe un transcript.json con conversación real y devuelve su ruta. */
function writeTranscript(): string {
  const path = join(dataDir, 'entrevista.transcript.json')
  writeFileSync(
    path,
    JSON.stringify({
      lines: [
        {
          channel: 'mic',
          text: '¿Cuándo fue la última vez que pasó?',
          startMs: 0,
          endMs: 900,
          receivedAtMs: 950,
          speaker: 0
        },
        {
          channel: 'system',
          text: 'El mes pasado, nos costó dos días de trabajo.',
          startMs: 1000,
          endMs: 1900,
          receivedAtMs: 1950,
          speaker: 0
        }
      ],
      latency: null,
      assistant: null,
      consent: null
    })
  )
  return path
}

/** Entrevista con 2 objetivos y transcript persistido. */
function seedInterview(): Interview {
  const discovery = repository.createDiscovery({ name: 'Discovery Maurya' })
  const created = repository.createInterview({
    discoveryId: discovery.id,
    title: 'Discovery con Acme'
  })
  return repository.updateInterview(created.id, {
    objectives: ['Objetivo cero', 'Objetivo uno'],
    transcriptPath: writeTranscript(),
    status: 'recorded'
  })
}

function userPrompt(): string {
  const params = harness.create.mock.calls[0][0] as {
    messages: Array<{ content: string }>
  }
  return params.messages[0].content
}

beforeEach(() => {
  vi.clearAllMocks()
  dataDir = mkdtempSync(join(tmpdir(), 'maurya-objective-outcomes-'))
  initStore(dataDir)
  process.env['ANTHROPIC_API_KEY'] = 'sk-ant-test-key'
})

afterEach(() => {
  delete process.env['ANTHROPIC_API_KEY']
})

describe('objectiveEvaluationService (questionOutcomes SPEC-039)', () => {
  // SPEC-039 · AC-22 (evaluación: sección de descartadas con motivo en el prompt)
  it('includes the discarded questions with their reasons in the evaluation prompt when the interview has questionOutcomes', async () => {
    const interview = seedInterview()
    // Camino real: recording:stop escribe los outcomes y el diálogo los motivos
    repository.setInterviewQuestionOutcomes(interview.id, [
      {
        question: '¿Cuándo fue la última vez que pasó?',
        outcome: 'discarded',
        reason: 'Ya lo había contado al principio'
      },
      { question: '¿Cuánto pagasteis por la solución actual?', outcome: 'discarded' },
      { question: '¿Quién decidió la compra?', outcome: 'answered' }
    ])
    harness.create.mockResolvedValue(sdkResponse(VALID_JSON))

    const updated = await evaluateInterviewObjectives(interview.id)

    const prompt = userPrompt()
    expect(prompt).toContain(
      '## Preguntas descartadas por el entrevistador (con su motivo)\n' +
        '- ¿Cuándo fue la última vez que pasó? — Motivo: Ya lo había contado al principio\n' +
        '- ¿Cuánto pagasteis por la solución actual? — Motivo: sin motivo indicado'
    )
    // Las respondidas alimentan SOLO la nota, no la evaluación de objetivos
    expect(prompt).not.toContain('¿Quién decidió la compra?')
    expect(prompt).not.toContain('Preguntas ya respondidas')
    // La evaluación sigue persistiendo su resultado alineado (regresión SPEC-025)
    expect(updated.objectiveResults).toHaveLength(2)
  })
})
